<?php
namespace App\Http\Controllers;use App\Models\Enquiry;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;
class EnquiryController extends Controller{public function store(Request $request):JsonResponse{$data=$request->validate(['name'=>['required','string','max:120'],'company'=>['nullable','string','max:160'],'email'=>['required','email','max:160'],'phone'=>['required','string','max:40'],'service'=>['nullable','string','max:120'],'position'=>['nullable','string','max:160'],'message'=>['required','string','max:5000'],'cv'=>['nullable','file','mimes:pdf,doc,docx','max:5120']]);$path=$request->file('cv')?->store('applications','local');$enquiry=Enquiry::create([...$data,'attachment'=>$path,'kind'=>$request->route()->getName()??$request->segment(2),'status'=>'new','meta'=>['ip'=>$request->ip(),'user_agent'=>$request->userAgent()]]);return response()->json(['message'=>'Your request has been received.','reference'=>'SNT-'.str_pad((string)$enquiry->id,6,'0',STR_PAD_LEFT)],201);}}
